template.css_template:
#{{ID}} .rep-top-bar {
    position: absolute;
    top: 0;
    left: 0;
    width: var(--v-width, 90%);
    box-sizing: border-box;
    min-height: auto;
    background: {{PRIMARY_BG}};
    color: {{TITLE_COLOR}};
    display: block;
    padding: 5px 30px;
    font-family: '{{FONT_FAMILY}}', 'Roboto Condensed', sans-serif;
    box-shadow: {{BOX_SHADOW}};
    opacity: 0;
    transform-origin: left center;
    transform: {{ANIMATION_IN_TRANSFORM}};
    transition: all {{ANIMATION_DURATION}}s {{ANIMATION_EASE}};
}
#{{ID}} .rep-title {
    font-size: {{TITLE_SIZE}}px;
    font-weight: {{TITLE_WEIGHT}};
    text-transform: {{TITLE_TRANSFORM}};
    white-space: pre-line;
    z-index: 2;
    letter-spacing: -0.5px;
    color: {{TITLE_COLOR}};
}
#{{ID}} .rep-side-graphic {
    position: absolute;
    right: 0;
    top: 0;
    bottom: 0;
    width: 400px;
    background: url('{{SIDE_IMAGE}}') center/cover;
    opacity: 0.8;
}
#{{ID}} .rep-side-graphic::before {
    content: '';
    position: absolute;
    top: 0; left: 0; right: 0; bottom: 0;
    background: linear-gradient(to right, {{PRIMARY_BG}} 0%, transparent 100%);
}

template.js_template:
(() => {
    const root = document.getElementById("{{ID}}");
    const container = root.querySelector(".rep-top-bar");
    root.__slt_show = () => {
        const tl = GSAPFX.standardIn(container, {{{ANIMATION_IN_JSON}}});
        const textTl = GSAPFX.applyTextEffect(root, {{{TEXT_ANIM_JSON}}});
        if (textTl) {
            if ({{{TEXT_ANIM_SYNC}}}) {
                tl.add(textTl, ">-0.1");
            } else {
                tl.add(textTl, 0);
            }
        }
        return tl;
    };
    root.__slt_hide = () => {
        const textTl = GSAPFX.applyTextOutEffect(root, {{{TEXT_ANIM_OUT_JSON}}});
        const tl = GSAPFX.standardOut(container, {{{ANIMATION_OUT_JSON}}});
        if (textTl) {
            const sync = {{{TEXT_ANIM_OUT_SYNC}}};
            if (sync) {
                const combined = gsap.timeline();
                combined.add(textTl);
                combined.add(tl, ">-0.1");
                return combined;
            } else {
                tl.add(textTl, 0);
            }
        }
        return tl;
    };
})();
